#include<bits/stdc++.h>
using namespace std;
struct node
{
	long long x,y,step;
	friend bool operator<(const node a,const node b)
	{
		return a.x<b.x||(a.x==b.x&&a.y<b.y)||(a.x==b.x&&a.y==b.y&&a.step<b.step);
	}
	friend bool operator==(const node a,const node b)
	{
		return a.x==b.x&&a.y==b.y;
	}
	node():x(0),y(0),step(0){}
	node(long long a,long long b,long long c):x(a),y(b),step(c){}
}a[50];
vector<node> a1,a2;
long long res[50],target_x,target_y,End,n;
void dfs(long long num,node now)
{
	if(num>End)
	{
		if(End==n/2)
		{
			a1.push_back(now);
		}
		if(End==n)
		{
			a2.push_back(now);
		}
		return;
	}
	node nxt=node(now.x+a[num].x,now.y+a[num].y,now.step+1);
	dfs(num+1,nxt);
	dfs(num+1,now);
}
int main()
{
	scanf("%lld",&n);
	scanf("%lld%lld",&target_x,&target_y);
	for(long long i=1;i<=n;i++)
	{
		scanf("%lld%lld",&a[i].x,&a[i].y);
	}
	End=n/2;
	dfs(1,node(0,0,0));
	End=n;
	dfs(n/2+1,node(0,0,0));
	sort(a1.begin(),a1.end());
	sort(a2.begin(),a2.end());
	long long temp1[25],temp2[25];
	long long size1=a1.size(),size2=a2.size();
	long long i=0,j=size2-1;
	while(i<size1&&j>=0)
	{
		if(a1[i].x+a2[j].x<target_x||(a1[i].x+a2[j].x==target_x&&a1[i].y+a2[j].y<target_y))
		{
			i++;
		}
		else if(a1[i].x+a2[j].x>target_x||(a1[i].x+a2[j].x==target_x&&a1[i].y+a2[j].y>target_y))
		{
			j--;
		}
		else
		{
			memset(temp1,0,sizeof(temp1));
			memset(temp2,0,sizeof(temp2));
			long long k=i;
			while(k<size1&&a1[k]==a1[i])
			{
				temp1[a1[k].step]++;
				k++;
			}
			i=k;
			k=j;
			while(k>=0&&a2[k]==a2[j])
			{
				temp2[a2[k].step]++;
				k--;
			}
			j=k;
			for(long long x=0;x<=20;x++)
			{
				for(long long y=0;y<=20;y++)
				{
					res[x+y]+=temp1[x]*temp2[y];
				}
			}
		}
	}
	for(i=1;i<=n;i++)
	{
		printf("%lld\n",res[i]);
	}
	return 0;
}
